import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Song {
  id: string;
  title: string;
  artist: string;
  url: string;
  duration: string; // Display string like "3:45"
}

export type Direction = 'UP' | 'DOWN' | 'LEFT' | 'RIGHT';

export interface Coordinate {
  x: number;
  y: number;
}

export enum GameStatus {
  IDLE = 'IDLE',
  PLAYING = 'PLAYING',
  GAME_OVER = 'GAME_OVER',
  PAUSED = 'PAUSED'
}

import { Song } from './types';

export const GRID_SIZE = 20;
export const INITIAL_SPEED = 150;
export const SPEED_INCREMENT = 2; // ms to decrease per food eaten

export const MUSIC_PLAYLIST: Song[] = [
  {
    id: '1',
    title: 'Neon Horizon',
    artist: 'AI Synth Gen v1',
    url: 'https://cdn.pixabay.com/download/audio/2022/11/22/audio_febc508520.mp3?filename=cyberpunk-2099-126346.mp3', 
    duration: '2:15'
  },
  {
    id: '2',
    title: 'Logic Gate Float',
    artist: 'Neural Network Beats',
    url: 'https://cdn.pixabay.com/download/audio/2022/03/15/audio_24e3e3f350.mp3?filename=future-technology-10375.mp3',
    duration: '1:58'
  },
  {
    id: '3',
    title: 'Binary Sunset',
    artist: 'Deep Learning Orchestra',
    url: 'https://cdn.pixabay.com/download/audio/2022/01/18/audio_d0a13f69d2.mp3?filename=synthwave-80s-110045.mp3',
    duration: '2:45'
  }
];

export const CONTROLS = {
  UP: ['ArrowUp', 'w', 'W'],
  DOWN: ['ArrowDown', 's', 'S'],
  LEFT: ['ArrowLeft', 'a', 'A'],
  RIGHT: ['ArrowRight', 'd', 'D'],
  PAUSE: [' ', 'Escape']
};

import React, { useState, useRef, useEffect } from 'react';
import { Play, Pause, SkipForward, SkipBack, Volume2, VolumeX, Music } from 'lucide-react';
import { Song } from '../types';
import { MUSIC_PLAYLIST } from '../constants';

interface MusicPlayerProps {
  currentSongIndex: number;
  setCurrentSongIndex: (index: number) => void;
}

const MusicPlayer: React.FC<MusicPlayerProps> = ({ currentSongIndex, setCurrentSongIndex }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [volume, setVolume] = useState(0.5);
  const [isMuted, setIsMuted] = useState(false);
  const audioRef = useRef<HTMLAudioElement>(null);

  const currentSong = MUSIC_PLAYLIST[currentSongIndex];

  // Handle song changes
  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.src = currentSong.url;
      if (isPlaying) {
        audioRef.current.play().catch(e => console.error("Playback failed", e));
      }
    }
  }, [currentSongIndex, currentSong.url]);

  // Handle play/pause toggle
  const togglePlay = () => {
    if (audioRef.current) {
      if (isPlaying) {
        audioRef.current.pause();
      } else {
        audioRef.current.play().catch(e => console.error("Playback failed", e));
      }
      setIsPlaying(!isPlaying);
    }
  };

  // Handle volume changes
  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = isMuted ? 0 : volume;
    }
  }, [volume, isMuted]);

  const handleNext = () => {
    setCurrentSongIndex((currentSongIndex + 1) % MUSIC_PLAYLIST.length);
  };

  const handlePrev = () => {
    setCurrentSongIndex((currentSongIndex - 1 + MUSIC_PLAYLIST.length) % MUSIC_PLAYLIST.length);
  };

  const handleEnded = () => {
    handleNext();
  };

  return (
    <div className="w-full max-w-md bg-black/80 backdrop-blur-md border border-neon-pink/50 rounded-xl p-6 shadow-neon-pink/20 relative overflow-hidden group">
      {/* Decorative background pulse */}
      <div className={`absolute inset-0 bg-gradient-to-r from-neon-pink/5 to-neon-purple/5 transition-opacity duration-1000 ${isPlaying ? 'opacity-100 animate-pulse' : 'opacity-20'}`}></div>

      <div className="relative z-10 flex flex-col gap-4">
        {/* Song Info */}
        <div className="flex items-center gap-4">
          <div className={`w-12 h-12 rounded-lg flex items-center justify-center bg-gradient-to-br from-purple-900 to-pink-900 shadow-inner border border-neon-pink/30 ${isPlaying ? 'animate-spin-slow' : ''}`}>
             <Music className="text-neon-pink w-6 h-6" />
          </div>
          <div className="flex-1 min-w-0">
            <h3 className="text-neon-pink font-orbitron font-bold truncate text-lg tracking-wide">{currentSong.title}</h3>
            <p className="text-gray-400 font-vt323 text-lg truncate">{currentSong.artist}</p>
          </div>
          <div className="font-vt323 text-neon-blue text-xl">{currentSong.duration}</div>
        </div>

        {/* Visualizer Bars (Fake) */}
        <div className="flex items-end justify-center gap-1 h-8 opacity-80">
          {[...Array(20)].map((_, i) => (
             <div 
               key={i} 
               className={`w-1.5 bg-neon-blue rounded-t-sm transition-all duration-300 ease-in-out`}
               style={{ 
                 height: isPlaying ? `${Math.random() * 100}%` : '10%',
                 opacity: isPlaying ? 1 : 0.3
               }}
             />
          ))}
        </div>

        {/* Controls */}
        <div className="flex items-center justify-between">
           <div className="flex items-center gap-2">
             <button onClick={() => setIsMuted(!isMuted)} className="text-gray-400 hover:text-white transition">
               {isMuted ? <VolumeX size={20} /> : <Volume2 size={20} />}
             </button>
             <input 
               type="range" 
               min="0" 
               max="1" 
               step="0.01" 
               value={isMuted ? 0 : volume}
               onChange={(e) => setVolume(parseFloat(e.target.value))}
               className="w-20 accent-neon-pink h-1 bg-gray-700 rounded-lg appearance-none cursor-pointer"
             />
           </div>

           <div className="flex items-center gap-4">
             <button onClick={handlePrev} className="text-gray-300 hover:text-neon-blue transition hover:scale-110">
               <SkipBack size={24} fill="currentColor" />
             </button>

             <button 
               onClick={togglePlay} 
               className="w-12 h-12 rounded-full bg-neon-pink text-black flex items-center justify-center shadow-neon-pink hover:scale-105 transition-transform active:scale-95"
             >
               {isPlaying ? <Pause size={24} fill="currentColor" /> : <Play size={24} fill="currentColor" className="ml-1" />}
             </button>

             <button onClick={handleNext} className="text-gray-300 hover:text-neon-blue transition hover:scale-110">
               <SkipForward size={24} fill="currentColor" />
             </button>
           </div>

           <div className="w-20"></div> {/* Spacer for balance */}
        </div>

        <audio 
          ref={audioRef} 
          onEnded={handleEnded}
          // Intentionally allowing audio to play in background even if not interacting directly with this element
        />
      </div>
    </div>
  );
};

