import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Coordinate, Direction, GameStatus } from '../types';
import { GRID_SIZE, INITIAL_SPEED, SPEED_INCREMENT, CONTROLS } from '../constants';
import { Trophy, RefreshCcw, Play, Pause, ChevronUp, ChevronDown, ChevronLeft, ChevronRight } from 'lucide-react';

const SnakeGame: React.FC = () => {
  const [snake, setSnake] = useState<Coordinate[]>([{ x: 10, y: 10 }]);
  const [food, setFood] = useState<Coordinate>({ x: 15, y: 5 });
  const [direction, setDirection] = useState<Direction>('RIGHT');
  const [status, setStatus] = useState<GameStatus>(GameStatus.IDLE);
  const [score, setScore] = useState(0);
  const [highScore, setHighScore] = useState(0);
  const [speed, setSpeed] = useState(INITIAL_SPEED);

  // Refs for state that changes rapidly to avoid closure staleness in event listeners
  const directionRef = useRef<Direction>('RIGHT');
  const gameIntervalRef = useRef<number | null>(null);

  // Generate random food position not on snake
  const generateFood = useCallback((currentSnake: Coordinate[]): Coordinate => {
    let newFood: Coordinate;
    let isOnSnake = true;
    while (isOnSnake) {
      newFood = {
        x: Math.floor(Math.random() * GRID_SIZE),
        y: Math.floor(Math.random() * GRID_SIZE)
      };
      // eslint-disable-next-line no-loop-func
      isOnSnake = currentSnake.some(segment => segment.x === newFood.x && segment.y === newFood.y);
      if (!isOnSnake) return newFood;
    }
    return { x: 0, y: 0 }; // Fallback
  }, []);

  const startGame = () => {
    setSnake([{ x: 10, y: 10 }]);
    setFood(generateFood([{ x: 10, y: 10 }]));
    setDirection('RIGHT');
    directionRef.current = 'RIGHT';
    setScore(0);
    setSpeed(INITIAL_SPEED);
    setStatus(GameStatus.PLAYING);
  };

  const togglePause = () => {
    if (status === GameStatus.PLAYING) {
      setStatus(GameStatus.PAUSED);
    } else if (status === GameStatus.PAUSED) {
      setStatus(GameStatus.PLAYING);
    }
  };

  const gameOver = () => {
    setStatus(GameStatus.GAME_OVER);
    if (score > highScore) {
      setHighScore(score);
    }
    if (gameIntervalRef.current) {
      clearInterval(gameIntervalRef.current);
    }
  };

  const changeDirection = useCallback((newDir: Direction) => {
    const currentDir = directionRef.current;

    // Prevent reversing into self
    if (newDir === 'UP' && currentDir === 'DOWN') return;
    if (newDir === 'DOWN' && currentDir === 'UP') return;
    if (newDir === 'LEFT' && currentDir === 'RIGHT') return;
    if (newDir === 'RIGHT' && currentDir === 'LEFT') return;

    directionRef.current = newDir;
    setDirection(newDir);
  }, []);

  const handleKeyDown = useCallback((e: KeyboardEvent) => {
    // Prevent default scrolling for game keys
    if ([...CONTROLS.UP, ...CONTROLS.DOWN, ...CONTROLS.LEFT, ...CONTROLS.RIGHT, ...CONTROLS.PAUSE].includes(e.key)) {
      e.preventDefault();
    }

    if (status === GameStatus.IDLE || status === GameStatus.GAME_OVER) return;

    // Handle Pause
    if (CONTROLS.PAUSE.includes(e.key)) {
      togglePause();
      return;
    }

    if (status !== GameStatus.PLAYING) return;

    if (CONTROLS.UP.includes(e.key)) changeDirection('UP');
    else if (CONTROLS.DOWN.includes(e.key)) changeDirection('DOWN');
    else if (CONTROLS.LEFT.includes(e.key)) changeDirection('LEFT');
    else if (CONTROLS.RIGHT.includes(e.key)) changeDirection('RIGHT');

  }, [status, changeDirection]);

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleKeyDown]);

  const moveSnake = useCallback(() => {
    if (status !== GameStatus.PLAYING) return;

    setSnake(prevSnake => {
      const head = prevSnake[0];
      const newHead = { ...head };

      switch (directionRef.current) {
        case 'UP': newHead.y -= 1; break;
        case 'DOWN': newHead.y += 1; break;
        case 'LEFT': newHead.x -= 1; break;
        case 'RIGHT': newHead.x += 1; break;
      }

      // Check Walls
      if (newHead.x < 0 || newHead.x >= GRID_SIZE || newHead.y < 0 || newHead.y >= GRID_SIZE) {
        gameOver();
        return prevSnake;
      }

      // Check Self
      if (prevSnake.some(segment => segment.x === newHead.x && segment.y === newHead.y)) {
        gameOver();
        return prevSnake;
      }

      const newSnake = [newHead, ...prevSnake];

      // Check Food
      if (newHead.x === food.x && newHead.y === food.y) {
        setScore(s => s + 10);
        setSpeed(s => Math.max(50, s - SPEED_INCREMENT));
        setFood(generateFood(newSnake));
        // Don't pop tail, so it grows
      } else {
        newSnake.pop(); // Remove tail
      }

      return newSnake;
    });
  }, [status, food, generateFood]);

  // Game Loop
  useEffect(() => {
    if (status === GameStatus.PLAYING) {
      gameIntervalRef.current = window.setInterval(moveSnake, speed);
    } else if (gameIntervalRef.current) {
      clearInterval(gameIntervalRef.current);
    }
    return () => {
      if (gameIntervalRef.current) clearInterval(gameIntervalRef.current);
    };
  }, [status, moveSnake, speed]);


  // Rendering Helpers
  const renderGrid = () => {
    const grid = [];
    for (let y = 0; y < GRID_SIZE; y++) {
      for (let x = 0; x < GRID_SIZE; x++) {
        let type = 'EMPTY';
        let isHead = false;

        if (food.x === x && food.y === y) type = 'FOOD';

        const snakeIndex = snake.findIndex(s => s.x === x && s.y === y);
        if (snakeIndex !== -1) {
          type = 'SNAKE';
          if (snakeIndex === 0) isHead = true;
        }

        grid.push(
          <div 
            key={`${x}-${y}`}
            className={`
              w-full h-full border-[0.5px] border-white/5
              ${type === 'SNAKE' ? (isHead ? 'bg-neon-green shadow-neon-green z-10' : 'bg-green-500/80') : ''}
              ${type === 'FOOD' ? 'bg-neon-pink shadow-neon-pink rounded-full scale-75 animate-pulse' : ''}
              ${type === 'EMPTY' ? 'bg-transparent' : ''}
            `}
          />
        );
      }
    }
    return grid;
  };

  return (
    <div className="flex flex-col items-center gap-4 w-full">

      {/* Score Board & Pause */}
      <div className="flex w-full justify-between items-center max-w-[400px] px-2 font-orbitron text-neon-green tracking-wider">
        <div className="flex flex-col">
           <span className="text-[10px] sm:text-xs text-gray-400">SCORE</span>
           <span className="text-xl sm:text-2xl font-bold">{score.toString().padStart(4, '0')}</span>
        </div>

        <div className="flex gap-4">
          <button 
            onClick={togglePause}
            disabled={status === GameStatus.IDLE || status === GameStatus.GAME_OVER}
            className={`w-10 h-10 flex items-center justify-center rounded-full border border-neon-green/30 text-neon-green hover:bg-neon-green/10 transition-colors ${status === GameStatus.IDLE || status === GameStatus.GAME_OVER ? 'opacity-30 cursor-not-allowed' : ''}`}
          >
            {status === GameStatus.PAUSED ? <Play size={20} fill="currentColor" /> : <Pause size={20} fill="currentColor" />}
          </button>
        </div>

        <div className="flex flex-col items-end">
           <span className="text-[10px] sm:text-xs text-gray-400 flex items-center gap-1"><Trophy size={12}/> BEST</span>
           <span className="text-xl sm:text-2xl font-bold text-neon-blue">{highScore.toString().padStart(4, '0')}</span>
        </div>
      </div>

      {/* Game Area */}
      <div className="relative group">
        <div 
          className="grid bg-black/50 backdrop-blur-sm border-2 border-neon-green shadow-neon-green rounded-lg overflow-hidden mx-auto"
          style={{
            gridTemplateColumns: `repeat(${GRID_SIZE}, 1fr)`,
            gridTemplateRows: `repeat(${GRID_SIZE}, 1fr)`,
            width: 'min(90vw, 400px)',
            height: 'min(90vw, 400px)'
          }}
        >
          {renderGrid()}
        </div>

        {/* Overlays */}
        {status === GameStatus.IDLE && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/80 backdrop-blur-sm z-20 rounded-lg">
            <h1 className="text-3xl sm:text-4xl font-orbitron text-neon-green font-bold mb-4 animate-pulse text-center">NEON<br/>SNAKE</h1>
            <button 
              onClick={startGame}
              className="flex items-center gap-2 px-6 py-3 bg-neon-green text-black font-bold rounded-none hover:bg-white transition-colors duration-200 font-orbitron clip-path-polygon"
              style={{ clipPath: 'polygon(10% 0, 100% 0, 100% 70%, 90% 100%, 0 100%, 0 30%)' }}
            >
              <Play size={20} /> START
            </button>
            <p className="mt-4 text-gray-400 font-vt323 text-lg hidden sm:block">Use Arrow Keys or WASD</p>
          </div>
        )}

        {status === GameStatus.PAUSED && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/60 backdrop-blur-sm z-20 rounded-lg">
            <h2 className="text-3xl font-orbitron text-white font-bold mb-4 tracking-widest">PAUSED</h2>
            <button 
              onClick={togglePause}
              className="w-16 h-16 rounded-full bg-neon-green/20 border-2 border-neon-green flex items-center justify-center text-neon-green hover:bg-neon-green hover:text-black transition-all"
            >
              <Play size={32} fill="currentColor" className="ml-1" />
            </button>
          </div>
        )}

        {status === GameStatus.GAME_OVER && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-red-900/40 backdrop-blur-sm z-20 rounded-lg">
            <h2 className="text-4xl sm:text-5xl font-orbitron text-red-500 font-bold mb-2 shadow-red-500 drop-shadow-lg text-center">GAME<br/>OVER</h2>
            <p className="text-xl font-vt323 text-white mb-6">Final Score: {score}</p>
            <button 
