        >
          <ChevronDown size={30} />
        </button>
        <button 
          onPointerDown={(e) => { e.preventDefault(); changeDirection('RIGHT'); }}
          className="w-14 h-14 bg-gray-800/80 rounded-lg border border-gray-600 active:bg-neon-green/50 active:border-neon-green flex items-center justify-center text-white transition-colors"
        >
