import React, { useState, useRef, useEffect } from 'react';
import { Play, Pause, SkipForward, SkipBack, Volume2, VolumeX, Music, ListMusic, X, Maximize2, Minimize2 } from 'lucide-react';
import { Song } from '../types';
import { MUSIC_PLAYLIST } from '../constants';

interface MusicPlayerProps {
  currentSongIndex: number;
  setCurrentSongIndex: (index: number) => void;
}

const MusicPlayer: React.FC<MusicPlayerProps> = ({ currentSongIndex, setCurrentSongIndex }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [volume, setVolume] = useState(0.5);
  const [isMuted, setIsMuted] = useState(false);
  const [showPlaylist, setShowPlaylist] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const audioRef = useRef<HTMLAudioElement>(null);

  const currentSong = MUSIC_PLAYLIST[currentSongIndex];

  // Handle song changes
  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.src = currentSong.url;
      if (isPlaying) {
        audioRef.current.play().catch(e => console.error("Playback failed", e));
      }
    }
  }, [currentSongIndex, currentSong.url]);

  // Handle play/pause toggle
  const togglePlay = () => {
    if (audioRef.current) {
      if (isPlaying) {
        audioRef.current.pause();
      } else {
        audioRef.current.play().catch(e => console.error("Playback failed", e));
      }
      setIsPlaying(!isPlaying);
    }
  };

  // Handle volume changes
  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = isMuted ? 0 : volume;
    }
  }, [volume, isMuted]);

  const handleNext = () => {
    setCurrentSongIndex((currentSongIndex + 1) % MUSIC_PLAYLIST.length);
  };

  const handlePrev = () => {
    setCurrentSongIndex((currentSongIndex - 1 + MUSIC_PLAYLIST.length) % MUSIC_PLAYLIST.length);
  };

  const handleEnded = () => {
    handleNext();
  };

  const selectSong = (index: number) => {
    setCurrentSongIndex(index);
    if (!isPlaying) {
      setIsPlaying(true);
      setTimeout(() => {
         audioRef.current?.play().catch(e => console.error("Playback failed", e));
      }, 50);
    }
    setShowPlaylist(false);
  };

  return (
    <div className={`w-full max-w-md bg-white/90 dark:bg-black/80 backdrop-blur-md border border-purple-300 dark:border-neon-pink/50 rounded-xl shadow-lg dark:shadow-neon-pink/20 relative overflow-hidden group transition-all duration-300 ${isMinimized ? 'p-2' : 'p-4 sm:p-6'}`}>

      {/* Decorative background pulse (only when expanded) */}
      {!isMinimized && (
        <div className={`absolute inset-0 bg-gradient-to-r from-purple-200/50 to-pink-200/50 dark:from-neon-pink/5 dark:to-neon-purple/5 transition-opacity duration-1000 ${isPlaying ? 'opacity-100 animate-pulse' : 'opacity-20'}`}></div>
      )}

      {/* Playlist Overlay */}
      {showPlaylist && !isMinimized && (
        <div className="absolute inset-0 bg-white dark:bg-black/95 z-20 flex flex-col animate-in fade-in slide-in-from-bottom-4 duration-300">
           <div className="p-4 border-b border-gray-200 dark:border-white/10 flex justify-between items-center">
             <h3 className="text-purple-600 dark:text-neon-pink font-orbitron font-bold">SELECT TRACK</h3>
             <button onClick={() => setShowPlaylist(false)} className="text-gray-500 dark:text-gray-400 hover:text-black dark:hover:text-white">
               <X size={20} />
             </button>
           </div>
           <div className="flex-1 overflow-y-auto p-2 space-y-1 custom-scrollbar">
              {MUSIC_PLAYLIST.map((song, idx) => (
                <button 
                  key={song.id}
                  onClick={() => selectSong(idx)}
                  className={`w-full text-left p-3 rounded-md flex items-center justify-between group transition-colors ${currentSongIndex === idx ? 'bg-purple-100 dark:bg-neon-pink/20 text-purple-900 dark:text-white' : 'hover:bg-gray-100 dark:hover:bg-white/5 text-gray-600 dark:text-gray-400'}`}
                >
                  <div className="flex flex-col">
                    <span className={`font-orbitron text-sm ${currentSongIndex === idx ? 'text-purple-600 dark:text-neon-pink' : 'group-hover:text-black dark:group-hover:text-white'}`}>{song.title}</span>
                    <span className="text-xs font-vt323">{song.artist}</span>
                  </div>
                  {currentSongIndex === idx && <div className="w-2 h-2 rounded-full bg-purple-500 dark:bg-neon-pink animate-pulse" />}
                </button>
              ))}
           </div>
        </div>
      )}

      <div className="relative z-10 flex flex-col gap-4">

        {/* Minimized View */}
        {isMinimized ? (
          <div className="flex items-center gap-3">
             <button 
               onClick={togglePlay} 
               className="w-10 h-10 rounded-full bg-purple-600 dark:bg-neon-pink text-white dark:text-black flex items-center justify-center shrink-0"
             >
               {isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" className="ml-1" />}
             </button>

             <div className="flex-1 min-w-0">
                <h3 className="text-purple-900 dark:text-neon-pink font-orbitron font-bold truncate text-sm">{currentSong.title}</h3>
                <p className="text-gray-600 dark:text-gray-400 font-vt323 text-xs truncate">{currentSong.artist}</p>
             </div>

             <button onClick={handleNext} className="text-gray-500 dark:text-gray-400 hover:text-purple-600 dark:hover:text-white">
               <SkipForward size={20} fill="currentColor" />
             </button>

             <button onClick={() => setIsMinimized(false)} className="text-gray-500 dark:text-gray-400 hover:text-purple-600 dark:hover:text-white p-1">
                <Maximize2 size={18} />
             </button>
          </div>
        ) : (
          /* Expanded View */
          <>
            {/* Song Info */}
            <div className="flex items-center gap-4">
              <div className={`w-12 h-12 rounded-lg flex items-center justify-center bg-gradient-to-br from-purple-500 to-pink-500 dark:from-purple-900 dark:to-pink-900 shadow-inner border border-purple-300 dark:border-neon-pink/30 ${isPlaying ? 'animate-spin-slow' : ''}`}>
                <Music className="text-white dark:text-neon-pink w-6 h-6" />
              </div>
              <div className="flex-1 min-w-0">
                <h3 className="text-purple-800 dark:text-neon-pink font-orbitron font-bold truncate text-lg tracking-wide">{currentSong.title}</h3>
                <p className="text-gray-600 dark:text-gray-400 font-vt323 text-lg truncate">{currentSong.artist}</p>
              </div>

              <div className="flex gap-2">
                 <button 
                  onClick={() => setIsMinimized(true)}
                  className="p-2 text-gray-500 dark:text-gray-400 hover:text-purple-600 dark:hover:text-white rounded-full transition-colors"
                  title="Minimize"
                >
                  <Minimize2 size={20} />
                </button>
                <button 
                  onClick={() => setShowPlaylist(!showPlaylist)}
                  className="p-2 text-teal-600 dark:text-neon-blue hover:text-black dark:hover:text-white hover:bg-black/5 dark:hover:bg-white/10 rounded-full transition-colors"
                  title="Playlist"
                >
                  <ListMusic size={24} />
                </button>
              </div>
            </div>

            {/* Visualizer Bars (Fake) */}
            <div className="flex items-end justify-center gap-1 h-8 opacity-80">
              {[...Array(20)].map((_, i) => (
                <div 
                  key={i} 
                  className={`w-1.5 bg-teal-500 dark:bg-neon-blue rounded-t-sm transition-all duration-300 ease-in-out`}
                  style={{ 
                    height: isPlaying ? `${Math.random() * 100}%` : '10%',
                    opacity: isPlaying ? 1 : 0.3
                  }}
                />
              ))}
            </div>

            {/* Controls */}
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <button onClick={() => setIsMuted(!isMuted)} className="text-gray-500 dark:text-gray-400 hover:text-black dark:hover:text-white transition">
                  {isMuted ? <VolumeX size={20} /> : <Volume2 size={20} />}
                </button>
                <input 
                  type="range" 
                  min="0" 
                  max="1" 
                  step="0.01" 
                  value={isMuted ? 0 : volume}
                  onChange={(e) => setVolume(parseFloat(e.target.value))}
                  className="w-16 sm:w-20 accent-purple-600 dark:accent-neon-pink h-1 bg-gray-300 dark:bg-gray-700 rounded-lg appearance-none cursor-pointer hidden sm:block"
                />
              </div>

              <div className="flex items-center gap-4">
                <button onClick={handlePrev} className="text-gray-400 dark:text-gray-300 hover:text-teal-600 dark:hover:text-neon-blue transition hover:scale-110">
                  <SkipBack size={24} fill="currentColor" />
                </button>

                <button 
                  onClick={togglePlay} 
                  className="w-12 h-12 rounded-full bg-purple-600 dark:bg-neon-pink text-white dark:text-black flex items-center justify-center shadow-lg dark:shadow-neon-pink hover:scale-105 transition-transform active:scale-95"
                >
                  {isPlaying ? <Pause size={24} fill="currentColor" /> : <Play size={24} fill="currentColor" className="ml-1" />}
                </button>

                <button onClick={handleNext} className="text-gray-400 dark:text-gray-300 hover:text-teal-600 dark:hover:text-neon-blue transition hover:scale-110">
                  <SkipForward size={24} fill="currentColor" />
                </button>
              </div>

              <div className="font-vt323 text-teal-700 dark:text-neon-blue text-xl w-16 text-right">
                {currentSong.duration}
              </div>
            </div>
          </>
        )}

        <audio 
          ref={audioRef} 
          onEnded={handleEnded}
        />
      </div>
    </div>
  );
};

export default MusicPlayer;

