import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Coordinate, Direction, GameStatus, LeaderboardEntry } from '../types';
import { GRID_SIZE, INITIAL_SPEED, SPEED_INCREMENT, CONTROLS } from '../constants';
import { Trophy, RefreshCcw, Play, Pause, ChevronUp, ChevronDown, ChevronLeft, ChevronRight, Save } from 'lucide-react';
import { playEatSound, playGameOverSound } from '../utils/sfx';

const LEADERBOARD_KEY = 'neon-snake-leaderboard';

const SnakeGame: React.FC = () => {
  const [snake, setSnake] = useState<Coordinate[]>([{ x: 10, y: 10 }]);
  const [food, setFood] = useState<Coordinate>({ x: 15, y: 5 });
  const [direction, setDirection] = useState<Direction>('RIGHT');
  const [status, setStatus] = useState<GameStatus>(GameStatus.IDLE);
  const [score, setScore] = useState(0);
  const [highScore, setHighScore] = useState(0);
  const [speed, setSpeed] = useState(INITIAL_SPEED);

  // Leaderboard State
  const [leaderboard, setLeaderboard] = useState<LeaderboardEntry[]>([]);
  const [playerName, setPlayerName] = useState('');
  const [showNameInput, setShowNameInput] = useState(false);

  // Refs
  const directionRef = useRef<Direction>('RIGHT');
  const gameIntervalRef = useRef<number | null>(null);

  // Load Leaderboard & High Score on Mount
  useEffect(() => {
    const storedLB = localStorage.getItem(LEADERBOARD_KEY);
    if (storedLB) {
      const parsed: LeaderboardEntry[] = JSON.parse(storedLB);
      setLeaderboard(parsed);
      if (parsed.length > 0) {
        setHighScore(Math.max(...parsed.map(e => e.score)));
      }
    }
  }, []);

  // Generate random food
  const generateFood = useCallback((currentSnake: Coordinate[]): Coordinate => {
    let newFood: Coordinate;
    let isOnSnake = true;
    while (isOnSnake) {
      newFood = {
        x: Math.floor(Math.random() * GRID_SIZE),
        y: Math.floor(Math.random() * GRID_SIZE)
      };
      // eslint-disable-next-line no-loop-func
      isOnSnake = currentSnake.some(segment => segment.x === newFood.x && segment.y === newFood.y);
      if (!isOnSnake) return newFood;
    }
    return { x: 0, y: 0 };
  }, []);

  const startGame = () => {
    setSnake([{ x: 10, y: 10 }]);
    setFood(generateFood([{ x: 10, y: 10 }]));
    setDirection('RIGHT');
    directionRef.current = 'RIGHT';
    setScore(0);
    setSpeed(INITIAL_SPEED);
    setStatus(GameStatus.PLAYING);
    setShowNameInput(false);
  };

  const togglePause = () => {
    if (status === GameStatus.PLAYING) {
      setStatus(GameStatus.PAUSED);
    } else if (status === GameStatus.PAUSED) {
      setStatus(GameStatus.PLAYING);
    }
  };

  const handleGameOver = () => {
    setStatus(GameStatus.GAME_OVER);
    playGameOverSound();

    if (score > highScore) {
      setHighScore(score);
    }

    if (gameIntervalRef.current) {
      clearInterval(gameIntervalRef.current);
    }

    // Check if score qualifies for leaderboard (Top 5)
    const qualifies = leaderboard.length < 5 || score > leaderboard[leaderboard.length - 1].score;
    if (qualifies && score > 0) {
      setShowNameInput(true);
      setPlayerName('');
    }
  };

  const saveScore = () => {
    if (!playerName.trim()) return;

    // Use name as typed, just trimmed
    const newEntry: LeaderboardEntry = {
      name: playerName.trim().slice(0, 15),
      score,
      date: new Date().toLocaleDateString()
    };

    const newLeaderboard = [...leaderboard, newEntry]
      .sort((a, b) => b.score - a.score)
      .slice(0, 5);

    setLeaderboard(newLeaderboard);
    localStorage.setItem(LEADERBOARD_KEY, JSON.stringify(newLeaderboard));
    setShowNameInput(false);
  };

  const changeDirection = useCallback((newDir: Direction) => {
    const currentDir = directionRef.current;

    if (newDir === 'UP' && currentDir === 'DOWN') return;
    if (newDir === 'DOWN' && currentDir === 'UP') return;
    if (newDir === 'LEFT' && currentDir === 'RIGHT') return;
    if (newDir === 'RIGHT' && currentDir === 'LEFT') return;

    directionRef.current = newDir;
    setDirection(newDir);
  }, []);

  const handleKeyDown = useCallback((e: KeyboardEvent) => {
    // CRITICAL FIX: If typing in the input, ignore game controls
    const target = e.target as HTMLElement;
    if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA') {
      // Allow Enter to save
      if (e.key === 'Enter') {
        saveScore();
      }
      return; 
    }

    if (status === GameStatus.IDLE || status === GameStatus.GAME_OVER) return;

    // Prevent scrolling/default behavior for game keys ONLY if not typing
    if ([...CONTROLS.UP, ...CONTROLS.DOWN, ...CONTROLS.LEFT, ...CONTROLS.RIGHT, ...CONTROLS.PAUSE].includes(e.key)) {
      e.preventDefault();
    }

    if (CONTROLS.PAUSE.includes(e.key)) {
      togglePause();
      return;
    }

    if (status !== GameStatus.PLAYING) return;

    if (CONTROLS.UP.includes(e.key)) changeDirection('UP');
    else if (CONTROLS.DOWN.includes(e.key)) changeDirection('DOWN');
    else if (CONTROLS.LEFT.includes(e.key)) changeDirection('LEFT');
    else if (CONTROLS.RIGHT.includes(e.key)) changeDirection('RIGHT');

  }, [status, changeDirection, playerName, saveScore]); // Added dependencies for saveScore logic

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleKeyDown]);

  const moveSnake = useCallback(() => {
    if (status !== GameStatus.PLAYING) return;

    setSnake(prevSnake => {
      const head = prevSnake[0];
      const newHead = { ...head };

      switch (directionRef.current) {
        case 'UP': newHead.y -= 1; break;
        case 'DOWN': newHead.y += 1; break;
        case 'LEFT': newHead.x -= 1; break;
        case 'RIGHT': newHead.x += 1; break;
      }

      // Check Walls
      if (newHead.x < 0 || newHead.x >= GRID_SIZE || newHead.y < 0 || newHead.y >= GRID_SIZE) {
        handleGameOver();
        return prevSnake;
      }

      // Check Self
      if (prevSnake.some(segment => segment.x === newHead.x && segment.y === newHead.y)) {
        handleGameOver();
        return prevSnake;
      }

      const newSnake = [newHead, ...prevSnake];

      // Check Food
      if (newHead.x === food.x && newHead.y === food.y) {
        setScore(s => s + 10);
        setSpeed(s => Math.max(50, s - SPEED_INCREMENT));
        setFood(generateFood(newSnake));
        playEatSound();
      } else {
        newSnake.pop(); 
      }

      return newSnake;
    });
  }, [status, food, generateFood, leaderboard]); 

  // Game Loop
  useEffect(() => {
    if (status === GameStatus.PLAYING) {
      gameIntervalRef.current = window.setInterval(moveSnake, speed);
    } else if (gameIntervalRef.current) {
      clearInterval(gameIntervalRef.current);
    }
    return () => {
      if (gameIntervalRef.current) clearInterval(gameIntervalRef.current);
    };
  }, [status, moveSnake, speed]);

  // Render Grid
  const renderGrid = () => {
    const grid = [];
    for (let y = 0; y < GRID_SIZE; y++) {
      for (let x = 0; x < GRID_SIZE; x++) {
        let type = 'EMPTY';
        let isHead = false;

        if (food.x === x && food.y === y) type = 'FOOD';

        const snakeIndex = snake.findIndex(s => s.x === x && s.y === y);
        if (snakeIndex !== -1) {
          type = 'SNAKE';
          if (snakeIndex === 0) isHead = true;
        }

        grid.push(
          <div 
            key={`${x}-${y}`}
            className={`
              w-full h-full border-[0.5px] border-white/5 dark:border-white/5 border-gray-300
              ${type === 'SNAKE' ? (isHead ? 'bg-purple-600 dark:bg-neon-green shadow-neon-green z-10' : 'bg-purple-400 dark:bg-green-500/80') : ''}
              ${type === 'FOOD' ? 'bg-pink-500 dark:bg-neon-pink shadow-neon-pink rounded-full scale-75 animate-pulse' : ''}
              ${type === 'EMPTY' ? 'bg-transparent' : ''}
            `}
          />
        );
      }
    }
    return grid;
  };

  return (
    <div className="flex flex-col items-center gap-2 w-full">

      {/* Score Board & Pause */}
      <div className="flex w-full justify-between items-center max-w-[400px] px-2 font-orbitron text-purple-700 dark:text-neon-green tracking-wider transition-colors duration-300">
        <div className="flex flex-col">
           <span className="text-[10px] sm:text-xs text-gray-500 dark:text-gray-400">SCORE</span>
           <span className="text-xl sm:text-2xl font-bold">{score.toString().padStart(4, '0')}</span>
        </div>

        <div className="flex gap-4">
          <button 
            onClick={togglePause}
            disabled={status === GameStatus.IDLE || status === GameStatus.GAME_OVER}
            className={`w-10 h-10 flex items-center justify-center rounded-full border border-purple-700/30 dark:border-neon-green/30 text-purple-700 dark:text-neon-green hover:bg-purple-700/10 dark:hover:bg-neon-green/10 transition-colors ${status === GameStatus.IDLE || status === GameStatus.GAME_OVER ? 'opacity-30 cursor-not-allowed' : ''}`}
          >
            {status === GameStatus.PAUSED ? <Play size={20} fill="currentColor" /> : <Pause size={20} fill="currentColor" />}
          </button>
        </div>

        <div className="flex flex-col items-end">
           <span className="text-[10px] sm:text-xs text-gray-500 dark:text-gray-400 flex items-center gap-1"><Trophy size={12}/> BEST</span>
           <span className="text-xl sm:text-2xl font-bold text-teal-600 dark:text-neon-blue">{highScore.toString().padStart(4, '0')}</span>
        </div>
      </div>

      {/* Game Area */}
      <div className="relative group">
        <div 
          className="grid bg-gray-100/50 dark:bg-black/50 backdrop-blur-sm border-2 border-purple-500 dark:border-neon-green shadow-lg dark:shadow-neon-green rounded-lg overflow-hidden mx-auto transition-colors duration-300"
          style={{
            gridTemplateColumns: `repeat(${GRID_SIZE}, 1fr)`,
            gridTemplateRows: `repeat(${GRID_SIZE}, 1fr)`,
            width: 'min(85vw, 400px)',
            height: 'min(85vw, 400px)'
          }}
        >
          {renderGrid()}
        </div>

        {/* Start Overlay */}
        {status === GameStatus.IDLE && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/80 dark:bg-black/80 backdrop-blur-sm z-20 rounded-lg transition-colors duration-300">
            <h1 className="text-3xl sm:text-4xl font-orbitron text-purple-600 dark:text-neon-green font-bold mb-4 animate-pulse text-center leading-tight">NEON<br/>SNAKE</h1>
            <button 
              onClick={startGame}
              className="flex items-center gap-2 px-6 py-3 bg-purple-600 dark:bg-neon-green text-white dark:text-black font-bold rounded-none hover:scale-105 transition-transform duration-200 font-orbitron clip-path-polygon"
              style={{ clipPath: 'polygon(10% 0, 100% 0, 100% 70%, 90% 100%, 0 100%, 0 30%)' }}
            >
              <Play size={20} /> START
            </button>
          </div>
        )}

        {/* Pause Overlay */}
        {status === GameStatus.PAUSED && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/60 dark:bg-black/60 backdrop-blur-sm z-20 rounded-lg transition-colors duration-300">
            <h2 className="text-3xl font-orbitron text-gray-800 dark:text-white font-bold mb-4 tracking-widest">PAUSED</h2>
            <button 
              onClick={togglePause}
              className="w-16 h-16 rounded-full bg-purple-500/20 dark:bg-neon-green/20 border-2 border-purple-500 dark:border-neon-green flex items-center justify-center text-purple-600 dark:text-neon-green hover:bg-purple-500 dark:hover:bg-neon-green hover:text-white dark:hover:text-black transition-all"
            >
              <Play size={32} fill="currentColor" className="ml-1" />
            </button>
          </div>
        )}

        {/* Game Over & Leaderboard Overlay */}
        {status === GameStatus.GAME_OVER && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-red-100/90 dark:bg-red-900/60 backdrop-blur-md z-20 rounded-lg p-4 transition-colors duration-300">
            <h2 className="text-3xl font-orbitron text-red-600 dark:text-red-500 font-bold mb-2 shadow-red-500 drop-shadow-lg text-center leading-tight">GAME OVER</h2>

            {showNameInput ? (
               <div className="flex flex-col items-center gap-2 mb-4 w-full max-w-[200px] animate-in slide-in-from-bottom-5">
                 <p className="font-vt323 text-lg text-purple-900 dark:text-neon-blue">NEW HIGH SCORE!</p>
                 <div className="flex gap-2 w-full">
                    <input 
                      ref={(input) => { if(input) input.focus(); }}
                      type="text"
                      maxLength={15}
                      value={playerName}
                      onChange={(e) => setPlayerName(e.target.value)}
                      placeholder="ENTER NAME"
                      autoComplete="off"
                      autoCorrect="off"
                      spellCheck="false"
                      className="w-full bg-white dark:bg-black/50 border border-purple-500 dark:border-neon-green rounded px-2 py-1 font-vt323 text-xl text-center text-black dark:text-white outline-none focus:ring-2 ring-purple-400 placeholder:text-gray-400"
                    />
                    <button 
                      onClick={saveScore}
                      className="bg-purple-600 dark:bg-neon-green text-white dark:text-black p-2 rounded hover:opacity-80"
                    >
                      <Save size={20} />
                    </button>
                 </div>
               </div>
            ) : (
              <div className="w-full max-w-[240px] mb-4">
                 <div className="flex justify-between items-center border-b border-gray-400 dark:border-gray-600 pb-1 mb-2">
                    <span className="font-orbitron text-xs text-gray-600 dark:text-gray-300">RANK</span>
                    <span className="font-orbitron text-xs text-gray-600 dark:text-gray-300">NAME</span>
                    <span className="font-orbitron text-xs text-gray-600 dark:text-gray-300">SCORE</span>
                 </div>
                 <div className="flex flex-col gap-1 text-sm font-vt323">
                    {leaderboard.length === 0 ? (
                      <p className="text-center text-gray-500">No High Scores Yet</p>
                    ) : (
                      leaderboard.map((entry, idx) => (
                        <div key={idx} className={`flex justify-between ${idx === 0 ? 'text-purple-600 dark:text-neon-yellow font-bold' : 'text-gray-800 dark:text-gray-300'}`}>
                           <span>#{idx + 1}</span>
                           <span>{entry.name}</span>
                           <span>{entry.score}</span>
                        </div>
                      ))
                    )}
                 </div>
              </div>
            )}

            <button 
              onClick={startGame}
              className="flex items-center gap-2 px-6 py-2 bg-red-500 text-white dark:text-black font-bold hover:bg-red-600 dark:hover:bg-white transition-colors duration-200 font-orbitron text-sm sm:text-base rounded shadow-lg"
            >
              <RefreshCcw size={18} /> PLAY AGAIN
            </button>
          </div>
        )}
      </div>

      {/* Mobile Controls (D-Pad) */}
      <div className="grid grid-cols-3 gap-2 mt-1 sm:mt-4">
        <div />
        <button 
          onPointerDown={(e) => { e.preventDefault(); changeDirection('UP'); }}
          className="w-12 h-12 sm:w-14 sm:h-14 bg-gray-200 dark:bg-gray-800/80 rounded-lg border border-gray-400 dark:border-gray-600 active:bg-purple-500 active:dark:bg-neon-green/50 active:border-purple-500 active:dark:border-neon-green flex items-center justify-center text-gray-700 dark:text-white transition-colors touch-none shadow-md"
        >
          <ChevronUp size={28} />
        </button>
        <div />

        <button 
          onPointerDown={(e) => { e.preventDefault(); changeDirection('LEFT'); }}
          className="w-12 h-12 sm:w-14 sm:h-14 bg-gray-200 dark:bg-gray-800/80 rounded-lg border border-gray-400 dark:border-gray-600 active:bg-purple-500 active:dark:bg-neon-green/50 active:border-purple-500 active:dark:border-neon-green flex items-center justify-center text-gray-700 dark:text-white transition-colors touch-none shadow-md"
        >
          <ChevronLeft size={28} />
        </button>
        <button 
          onPointerDown={(e) => { e.preventDefault(); changeDirection('DOWN'); }}
          className="w-12 h-12 sm:w-14 sm:h-14 bg-gray-200 dark:bg-gray-800/80 rounded-lg border border-gray-400 dark:border-gray-600 active:bg-purple-500 active:dark:bg-neon-green/50 active:border-purple-500 active:dark:border-neon-green flex items-center justify-center text-gray-700 dark:text-white transition-colors touch-none shadow-md"
        >
          <ChevronDown size={28} />
        </button>
        <button 
          onPointerDown={(e) => { e.preventDefault(); changeDirection('RIGHT'); }}
          className="w-12 h-12 sm:w-14 sm:h-14 bg-gray-200 dark:bg-gray-800/80 rounded-lg border border-gray-400 dark:border-gray-600 active:bg-purple-500 active:dark:bg-neon-green/50 active:border-purple-500 active:dark:border-neon-green flex items-center justify-center text-gray-700 dark:text-white transition-colors touch-none shadow-md"
        >
          <ChevronRight size={28} />
        </button>
      </div>
    </div>
  );
};

