import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Coordinate, Direction, GameStatus, LeaderboardEntry, Difficulty } from '../types';
import { GRID_SIZE, DIFFICULTY_SPEEDS, SPEED_INCREMENT, CONTROLS } from '../constants';
import { playEatSound, playGameOverSound, playStartSound } from '../utils/sfx';

const LEADERBOARD_KEY = 'neon-snake-leaderboard';
const DIFFICULTIES: Difficulty[] = ['EASY', 'MEDIUM', 'HARD'];

const SnakeGame: React.FC = () => {
  const [snake, setSnake] = useState<Coordinate[]>([{ x: 10, y: 10 }]);
  const [food, setFood] = useState<Coordinate>({ x: 15, y: 5 });
  const [direction, setDirection] = useState<Direction>('RIGHT');
  const [status, setStatus] = useState<GameStatus>(GameStatus.IDLE);
  const [score, setScore] = useState(0);
  const [highScore, setHighScore] = useState(0);
  const [speed, setSpeed] = useState(DIFFICULTY_SPEEDS.MEDIUM);

  // Menu State
  const [menuIndex, setMenuIndex] = useState(1); // Default to MEDIUM

  // Leaderboard State
  const [leaderboard, setLeaderboard] = useState<LeaderboardEntry[]>([]);
  const [playerName, setPlayerName] = useState('');
  const [showNameInput, setShowNameInput] = useState(false);

  // Refs
  const directionRef = useRef<Direction>('RIGHT');
  const gameIntervalRef = useRef<number | null>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Load Leaderboard & High Score on Mount
  useEffect(() => {
    const storedLB = localStorage.getItem(LEADERBOARD_KEY);
    if (storedLB) {
      const parsed: LeaderboardEntry[] = JSON.parse(storedLB);
      setLeaderboard(parsed);
      if (parsed.length > 0) {
        setHighScore(Math.max(...parsed.map(e => e.score)));
      }
    }
  }, []);

  // Generate random food
  const generateFood = useCallback((currentSnake: Coordinate[]): Coordinate => {
    let newFood: Coordinate;
    let isOnSnake = true;
    while (isOnSnake) {
      newFood = {
        x: Math.floor(Math.random() * GRID_SIZE),
        y: Math.floor(Math.random() * GRID_SIZE)
      };
      // eslint-disable-next-line no-loop-func
      isOnSnake = currentSnake.some(segment => segment.x === newFood.x && segment.y === newFood.y);
      if (!isOnSnake) return newFood;
    }
    return { x: 0, y: 0 };
  }, []);

  const startGame = (difficulty: Difficulty) => {
    playStartSound();
    setSnake([{ x: 10, y: 10 }]);
    setFood(generateFood([{ x: 10, y: 10 }]));
    setDirection('RIGHT');
    directionRef.current = 'RIGHT';
    setScore(0);
    setSpeed(DIFFICULTY_SPEEDS[difficulty]);
    setStatus(GameStatus.PLAYING);
    setShowNameInput(false);
  };

  const resetToMenu = () => {
    setStatus(GameStatus.IDLE);
    setScore(0);
    setSnake([{ x: 10, y: 10 }]);
  };

  const togglePause = () => {
    if (status === GameStatus.PLAYING) {
      setStatus(GameStatus.PAUSED);
    } else if (status === GameStatus.PAUSED) {
      setStatus(GameStatus.PLAYING);
    }
  };

  // Unified Action Handler (Start/Select/Enter)
  const handleConfirmAction = () => {
    if (status === GameStatus.IDLE) {
      startGame(DIFFICULTIES[menuIndex]);
    } else if (status === GameStatus.GAME_OVER) {
       if (showNameInput) {
         saveScore();
       } else {
         resetToMenu();
       }
    } else if (status === GameStatus.PLAYING || status === GameStatus.PAUSED) {
      togglePause();
    }
  };

  const handleGameOver = () => {
    setStatus(GameStatus.GAME_OVER);
    playGameOverSound();

    if (score > highScore) {
      setHighScore(score);
    }

    if (gameIntervalRef.current) {
      clearInterval(gameIntervalRef.current);
    }

    // Check if score qualifies for leaderboard (Top 10)
    // We allow top 10 now
    const qualifies = leaderboard.length < 10 || score > leaderboard[leaderboard.length - 1].score;
    if (qualifies && score > 0) {
      setShowNameInput(true);
      setPlayerName('');
      setTimeout(() => {
        if (inputRef.current) {
          inputRef.current.focus();
        }
      }, 100);
    }
  };

  const saveScore = () => {
    if (!playerName.trim()) return;

    const newEntry: LeaderboardEntry = {
      name: playerName.trim().slice(0, 15),
      score,
      date: new Date().toLocaleDateString()
    };

    const newLeaderboard = [...leaderboard, newEntry]
      .sort((a, b) => b.score - a.score)
      .slice(0, 10); // Keep top 10

    setLeaderboard(newLeaderboard);
    localStorage.setItem(LEADERBOARD_KEY, JSON.stringify(newLeaderboard));
    setShowNameInput(false);
  };

  const changeDirection = useCallback((newDir: Direction) => {
    const currentDir = directionRef.current;

    if (newDir === 'UP' && currentDir === 'DOWN') return;
    if (newDir === 'DOWN' && currentDir === 'UP') return;
    if (newDir === 'LEFT' && currentDir === 'RIGHT') return;
    if (newDir === 'RIGHT' && currentDir === 'LEFT') return;

    directionRef.current = newDir;
    setDirection(newDir);
  }, []);

  const handleKeyDown = useCallback((e: KeyboardEvent) => {
    const target = e.target as HTMLElement;

    if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA') {
      if (e.key === 'Enter') {
        saveScore();
      }
      return; 
    }

    if (status === GameStatus.IDLE) {
      if (CONTROLS.UP.includes(e.key)) {
        setMenuIndex(prev => (prev > 0 ? prev - 1 : 2));
        e.preventDefault();
      } else if (CONTROLS.DOWN.includes(e.key)) {
        setMenuIndex(prev => (prev < 2 ? prev + 1 : 0));
        e.preventDefault();
      } else if (e.key === 'Enter' || CONTROLS.PAUSE.includes(e.key)) {
        handleConfirmAction();
        e.preventDefault();
      }
      return;
    }

    if (status === GameStatus.GAME_OVER) {
       if (e.key === 'Enter' || CONTROLS.PAUSE.includes(e.key)) {
          if (!showNameInput) {
            resetToMenu();
            e.preventDefault();
          } else {
            saveScore();
            e.preventDefault();
          }
       }
       return;
    }

    if ([...CONTROLS.UP, ...CONTROLS.DOWN, ...CONTROLS.LEFT, ...CONTROLS.RIGHT, ...CONTROLS.PAUSE].includes(e.key)) {
      e.preventDefault();
    }

    if (CONTROLS.PAUSE.includes(e.key)) {
      togglePause();
      return;
    }

    if (status !== GameStatus.PLAYING) return;

    if (CONTROLS.UP.includes(e.key)) changeDirection('UP');
    else if (CONTROLS.DOWN.includes(e.key)) changeDirection('DOWN');
    else if (CONTROLS.LEFT.includes(e.key)) changeDirection('LEFT');
    else if (CONTROLS.RIGHT.includes(e.key)) changeDirection('RIGHT');

  }, [status, changeDirection, playerName, saveScore, menuIndex, showNameInput]);

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleKeyDown]);

  const moveSnake = useCallback(() => {
    if (status !== GameStatus.PLAYING) return;

    setSnake(prevSnake => {
      const head = prevSnake[0];
      const newHead = { ...head };

      switch (directionRef.current) {
        case 'UP': newHead.y -= 1; break;
        case 'DOWN': newHead.y += 1; break;
        case 'LEFT': newHead.x -= 1; break;
        case 'RIGHT': newHead.x += 1; break;
      }

      if (newHead.x < 0 || newHead.x >= GRID_SIZE || newHead.y < 0 || newHead.y >= GRID_SIZE) {
        handleGameOver();
        return prevSnake;
      }

      if (prevSnake.some(segment => segment.x === newHead.x && segment.y === newHead.y)) {
        handleGameOver();
        return prevSnake;
      }

      const newSnake = [newHead, ...prevSnake];

      if (newHead.x === food.x && newHead.y === food.y) {
        setScore(s => s + 10);
        setSpeed(s => Math.max(50, s - SPEED_INCREMENT));
        setFood(generateFood(newSnake));
        playEatSound();
      } else {
        newSnake.pop(); 
      }

      return newSnake;
    });
  }, [status, food, generateFood, leaderboard]); 

  useEffect(() => {
    if (status === GameStatus.PLAYING) {
      gameIntervalRef.current = window.setInterval(moveSnake, speed);
    } else if (gameIntervalRef.current) {
      clearInterval(gameIntervalRef.current);
    }
    return () => {
      if (gameIntervalRef.current) clearInterval(gameIntervalRef.current);
    };
  }, [status, moveSnake, speed]);

  const renderGrid = () => {
    const grid = [];
    for (let y = 0; y < GRID_SIZE; y++) {
      for (let x = 0; x < GRID_SIZE; x++) {
        let type = 'EMPTY';
        let isHead = false;

        if (food.x === x && food.y === y) type = 'FOOD';

        const snakeIndex = snake.findIndex(s => s.x === x && s.y === y);
        if (snakeIndex !== -1) {
          type = 'SNAKE';
          if (snakeIndex === 0) isHead = true;
        }

        grid.push(
          <div 
            key={`${x}-${y}`}
            className={`
              w-full h-full border-[0.5px] border-white/5 dark:border-white/5
              ${type === 'SNAKE' ? (isHead ? 'bg-purple-800 dark:bg-black z-10' : 'bg-purple-600 dark:bg-black/60') : ''}
              ${type === 'FOOD' ? 'bg-pink-600 dark:bg-black rounded-full scale-75 border-2 border-black dark:border-black' : ''}
              ${type === 'EMPTY' ? 'bg-transparent' : ''}
            `}
          />
        );
      }
    }
    return grid;
  };

  return (
    <div className="relative flex flex-col items-center select-none">

      {/* GAME BOY CHASSIS */}
      <div className="relative bg-gray-300 dark:bg-slate-800 rounded-b-3xl rounded-t-lg shadow-[0_0_15px_rgba(0,0,0,0.3)] dark:shadow-[0_0_20px_rgba(0,0,0,0.6)] p-4 sm:p-6 w-[360px] sm:w-[440px] border-b-8 border-r-8 border-gray-400 dark:border-slate-900 transition-colors duration-500">

        {/* TOP BEZEL DECORATION */}
        <div className="absolute top-0 left-4 right-4 h-[2px] bg-gray-400 dark:bg-slate-700"></div>
        <div className="flex justify-between px-2 mb-2 text-[10px] font-orbitron text-gray-500 dark:text-gray-500 font-bold">
           <span>STEREO SOUND</span>
           <span>BATTERY</span>
        </div>

        {/* SCREEN AREA (BEZEL) */}
        <div className="bg-gray-500 dark:bg-gray-700 rounded-t-lg rounded-br-[40px] rounded-bl-lg p-3 sm:p-4 pt-3 shadow-inner relative">

          {/* POWER LED */}
          <div className="absolute top-[40%] left-2 flex flex-col items-center gap-1">
             <div className="w-2 h-2 rounded-full bg-red-500 shadow-[0_0_5px_red] animate-pulse"></div>
             <span className="text-[8px] font-bold text-gray-700 dark:text-gray-900 -ml-1">BAT.</span>
          </div>

          {/* THE ACTUAL LCD SCREEN */}
          <div className="bg-[#9ca04c] dark:bg-[#8bac0f] border-4 border-gray-600 dark:border-black shadow-inner overflow-hidden relative" style={{ boxShadow: 'inset 0 0 10px rgba(0,0,0,0.3)' }}>

             {/* LCD PIXEL GRID OVERLAY */}
             <div className="absolute inset-0 pointer-events-none z-0 opacity-10 bg-[size:2px_2px] bg-[rgba(0,0,0,0.1)]"></div>

             {/* HUD INSIDE SCREEN */}
             <div className="flex justify-between px-2 pt-1 font-vt323 text-[#0f380f] dark:text-[#0f380f] z-10 relative text-lg leading-none border-b border-[#0f380f]/20 pb-1">
                <span>SC:{score}</span>
                <span>HI:{highScore}</span>
             </div>

             {/* GAME GRID */}
             <div 
               className="grid relative z-10"
               style={{
                 gridTemplateColumns: `repeat(${GRID_SIZE}, 1fr)`,
                 gridTemplateRows: `repeat(${GRID_SIZE}, 1fr)`,
                 aspectRatio: '1/1',
               }}
             >
                {renderGrid()}
             </div>

             {/* SCREEN OVERLAYS (MENUS) */}

             {/* START MENU / DIFFICULTY */}
             {status === GameStatus.IDLE && (
                <div className="absolute inset-0 bg-[#9ca04c]/95 dark:bg-[#8bac0f]/95 z-20 flex flex-col items-center justify-center p-6 text-[#0f380f]">
                  <h1 className="text-4xl font-vt323 font-bold mb-2 tracking-widest">GAME BOT</h1>
                  <p className="text-lg font-vt323 mb-4 font-bold opacity-80">SELECT DIFFICULTY</p>
                  <div className="flex flex-col gap-3 w-full px-2">
                     {DIFFICULTIES.map((diff, idx) => (
                       <button
                         key={diff}
                         onClick={() => startGame(diff)}
                         onMouseEnter={() => setMenuIndex(idx)}
                         className={`border-4 border-[#0f380f] text-xl font-vt323 py-2 uppercase transition-all flex items-center justify-center relative font-bold tracking-widest ${menuIndex === idx ? 'bg-[#0f380f] text-[#9ca04c] dark:text-[#8bac0f] scale-105 shadow-lg' : 'text-[#0f380f] hover:bg-[#0f380f] hover:text-[#9ca04c] dark:hover:text-[#8bac0f] opacity-70 hover:opacity-100'}`}
                       >
                         {/* Cursor Arrow for selected item */}
                         {menuIndex === idx && <span className="absolute left-4 text-base animate-pulse">►</span>}
                         {diff}
                       </button>
                     ))}
                  </div>
                </div>
             )}

             {/* PAUSE */}
             {status === GameStatus.PAUSED && (
               <div className="absolute inset-0 bg-[#0f380f]/20 z-20 flex items-center justify-center">
                  <div className="bg-[#0f380f] text-[#9ca04c] px-6 py-2 border-4 border-[#9ca04c] font-vt323 text-3xl font-bold animate-pulse tracking-widest shadow-xl">
                    PAUSED
                  </div>
               </div>
             )}

             {/* GAME OVER */}
             {status === GameStatus.GAME_OVER && (
               <div className="absolute inset-0 bg-[#9ca04c]/95 dark:bg-[#8bac0f]/95 z-20 flex flex-col items-center justify-center p-4 text-[#0f380f]">
                  <h2 className="text-4xl font-vt323 font-bold mb-2">GAME OVER</h2>

                  {showNameInput ? (
                     <div className="flex flex-col items-center w-full gap-3 animate-in zoom-in duration-300">
                        <span className="text-xl font-vt323 animate-bounce">NEW HIGH SCORE!</span>
                        <input 
                           ref={inputRef}
                           type="text"
                           autoFocus
                           maxLength={10}
                           value={playerName}
                           onChange={(e) => setPlayerName(e.target.value)}
                           className="bg-[#0f380f]/10 border-b-4 border-[#0f380f] text-[#0f380f] text-center font-vt323 text-3xl w-4/5 outline-none placeholder-[#0f380f]/30 uppercase rounded-none py-1"
                           placeholder="TYPE NAME"
                           autoComplete="off"
                        />
                        <button onClick={saveScore} className="text-lg font-vt323 border-2 border-[#0f380f] px-6 py-1 hover:bg-[#0f380f] hover:text-[#8bac0f] mt-2 font-bold transition-colors">
                          SUBMIT (SELECT)
                        </button>
                     </div>
                  ) : (
                     <div className="w-full text-center">
                        <div className="text-sm font-vt323 border-b-2 border-[#0f380f] mb-2 pb-1 font-bold">TOP SCORES</div>
                        <div className="space-y-1 mb-4 h-[120px] overflow-y-auto no-scrollbar">
                          {leaderboard.length === 0 ? (
                            <div className="text-sm font-vt323 pt-4 italic opacity-70">NO SCORES YET</div>
                          ) : (
                            leaderboard.map((e, i) => (
                              <div key={i} className="flex justify-between text-base font-vt323 px-6 font-bold">
                                  <span>{i+1}. {e.name}</span>
                                  <span>{e.score}</span>
                              </div>
                            ))
                          )}
                        </div>
                        <button onClick={resetToMenu} className="mt-2 text-xl border-2 border-[#0f380f] px-6 py-1 hover:bg-[#0f380f] hover:text-[#8bac0f] font-vt323 font-bold transition-colors">
                           TRY AGAIN
                        </button>
                     </div>
                  )}
               </div>
             )}

          </div>

          {/* BRANDING */}
          <div className="text-center mt-2">
             <span className="font-orbitron font-bold italic text-gray-600 dark:text-gray-500 text-xl tracking-wider">GAME <span className="text-purple-600 dark:text-neon-blue">BOT</span></span>
          </div>

        </div>

        {/* CONTROLS AREA */}
        <div className="mt-8 mb-4 relative">

           <div className="flex justify-between items-end px-4">

              {/* D-PAD: Increased Size to w-60 h-60 (approx 240px) */}
              <div className="relative w-60 h-60">
                 <div className="absolute top-0 left-[34%] w-[32%] h-full bg-gray-800 dark:bg-black rounded shadow-md"></div>
                 <div className="absolute top-[34%] left-0 w-full h-[32%] bg-gray-800 dark:bg-black rounded shadow-md"></div>
                 <div className="absolute top-[34%] left-[34%] w-[32%] h-[32%] bg-gray-700/50 rounded-full"></div> {/* Center dimple */}

                 {/* Hit Areas */}
                 <button 
                   className="absolute top-0 left-[34%] w-[32%] h-[34%] hover:bg-white/10 active:bg-white/20"
                   onPointerDown={(e) => { 
                      e.preventDefault(); 
                      if(status === GameStatus.IDLE) {
                         setMenuIndex(prev => (prev > 0 ? prev - 1 : 2));
                      } else {
                         changeDirection('UP'); 
                      }
                   }}
                 />
                 <button 
                   className="absolute bottom-0 left-[34%] w-[32%] h-[34%] hover:bg-white/10 active:bg-white/20"
                   onPointerDown={(e) => { 
                      e.preventDefault(); 
                      if(status === GameStatus.IDLE) {
                         setMenuIndex(prev => (prev < 2 ? prev + 1 : 0));
                      } else {
                         changeDirection('DOWN'); 
                      }
                   }}
                 />
                 <button 
                   className="absolute top-[34%] left-0 w-[34%] h-[32%] hover:bg-white/10 active:bg-white/20"
                   onPointerDown={(e) => { e.preventDefault(); changeDirection('LEFT'); }}
                 />
                 <button 
                   className="absolute top-[34%] right-0 w-[34%] h-[32%] hover:bg-white/10 active:bg-white/20"
                   onPointerDown={(e) => { e.preventDefault(); changeDirection('RIGHT'); }}
                 />
              </div>

              {/* ACTION BUTTONS */}
              <div className="flex gap-4 transform -rotate-12 mb-2">
                 <div className="flex flex-col items-center gap-1 mt-4">
                    <button 
                       onClick={togglePause}
                       className="w-14 h-14 rounded-full bg-purple-700 dark:bg-neon-pink shadow-[0_4px_0_#4a1d96] dark:shadow-[0_4px_0_#990099] active:shadow-none active:translate-y-[4px] transition-all"
                    ></button>
                    <span className="font-orbitron font-bold text-gray-500 dark:text-gray-400 text-sm">B</span>
                 </div>
                 <div className="flex flex-col items-center gap-1 -mt-2">
                    <button 
                       onClick={handleConfirmAction}
                       className="w-14 h-14 rounded-full bg-purple-700 dark:bg-neon-pink shadow-[0_4px_0_#4a1d96] dark:shadow-[0_4px_0_#990099] active:shadow-none active:translate-y-[4px] transition-all"
                    ></button>
                    <span className="font-orbitron font-bold text-gray-500 dark:text-gray-400 text-sm">A</span>
                 </div>
              </div>
           </div>

           {/* START / SELECT */}
           <div className="flex justify-center gap-6 mt-12">
              <div className="flex flex-col items-center transform rotate-12">
                 <button 
                   onClick={handleConfirmAction}
                   className="w-16 h-4 bg-gray-500 dark:bg-gray-700 rounded-full shadow-inner border border-black/20 active:bg-gray-600 transition-colors"
                 ></button>
                 <span className="font-orbitron font-bold text-gray-500 dark:text-gray-400 text-xs mt-1 tracking-widest">SELECT</span>
              </div>
              <div className="flex flex-col items-center transform rotate-12">
                 <button 
                   onClick={handleConfirmAction}
                   className="w-16 h-4 bg-gray-500 dark:bg-gray-700 rounded-full shadow-inner border border-black/20 active:bg-gray-600 transition-colors"
                 ></button>
                 <span className="font-orbitron font-bold text-gray-500 dark:text-gray-400 text-xs mt-1 tracking-widest">START</span>
              </div>
           </div>

           {/* SPEAKER GRILL */}
           <div className="absolute bottom-0 right-6 flex gap-1.5 transform -rotate-12 opacity-50">
             <div className="w-1.5 h-10 bg-black/20 rounded-full"></div>
             <div className="w-1.5 h-10 bg-black/20 rounded-full"></div>
             <div className="w-1.5 h-10 bg-black/20 rounded-full"></div>
             <div className="w-1.5 h-10 bg-black/20 rounded-full"></div>
             <div className="w-1.5 h-10 bg-black/20 rounded-full"></div>
             <div className="w-1.5 h-10 bg-black/20 rounded-full"></div>
           </div>

        </div>

      </div>
    </div>
  );
};

